nto any specific aspect—such as technical details of the MCP preview, AI spending impact, or how OpenAI’s multi-cloud shift affects developer strategy.","annotations":[{"type":"url_citation","url":"https://azurecharts.com/updates?monthback=0","start_index":741,"end_index":805,"title":"Azure Updates in May 2026"},{"type":"url_citation","url":"https://francescomolfese.it/2026/05/azure-iaas-and-azure-local-announcements-and-updates-2026-weeks-19-20/","start_index":1204,"end_index":1335,"title":"Azure IaaS and Azure Local: announcements and updates (May 2026 – Weeks ..."},{"type":"url_citation","url":"https://www.infoq.com/news/2026/05/azure-linux-4-server/","start_index":1682,"end_index":1753,"title":"Microsoft Announces Azure Linux 4.0, Its First General-Purpose Server Linux Distribution"},{"type":"url_citation","url":"https://www.msn.com/en-us/money/news/microsofts-ai-momentum-builds-analyst-sees-copilot-seats-topping-25-million-azure-growth-above-40/ar-AA247DeW","start_index":2061,"end_index":2220,"title":"Microsoft's AI momentum builds: Analyst sees Copilot seats topping 25 million, Azure growth above 40%"},{"type":"url_citation","url":"https://tech-insider.org/microsoft-mai-in-house-ai-models-openai-2026/","start_index":2399,"end_index":2491,"title":"Microsoft In-House AI Models: MAI Strategy vs OpenAI (2026)"},{"type":"url_citation","url":"https://tech-insider.org/microsoft-ai-spending-azure-copilot-2026/","start_index":2718,"end_index":2806,"title":"Microsoft AI Spending 2026: $150B Capex [Analysis]"},{"type":"url_citation","url":"https://blogs.microsoft.com/blog/2026/04/27/the-next-phase-of-the-microsoft-openai-partnership/","start_index":3496,"end_index":3616,"title":"The next phase of the Microsoft-OpenAI partnership"},{"type":"url_citation","url":"https://thenewstack.io/openai-microsoft-partnership-restructured/","start_index":3851,"end_index":3936,"title":"Microsoft-OpenAI rewrite opens the door for Anthropic and Google"},{"type":"url_citation","url":"https